   290→{
   291→
   292→    bool flag = false;
   293→    float min = 0.0;
   294→    int triangle_index, ignore = 1;
   295→    vec3 v0, v1, v2;
   296→    vec3 reflect_position, reflect_dir;
   297→    vec3 front_triangle_v0, front_triangle_v1, front_triangle_v2;
   298→    front_triangle_v0 = vec3(-0.76f, -0.87f, -1.0f);
   299→    front_triangle_v1 = vec3(-0.76f, 1.0f, -1.0f);
   300→    front_triangle_v2 = vec3(1.31f, 1.0f, -1.0f);
