    74→    vec3 e1 = v1 - v0;
    75→    vec3 e2 = v2 - v0;
    76→    vec3 pvec = glm::cross(dir, e2);
    77→    float det = glm::dot(e1, pvec);
    78→    if (fabs(det) < EPSILON)
    79→        return false;
    80→
    81→    float invDet = 1.0f / det;
    82→    vec3 tvec = orig - v0;
    83→    u = glm::dot(tvec, pvec) * invDet;
    84→    if (u < 0.0f || u > 1.0f)
